# terraform/route53-failover.tf — DNS failover routing for Claude service
resource "aws_route53_health_check" "primary" {
  fqdn              = "claude-app.us-east-1.internal.company.com"
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health/ready"
  failure_threshold = 3          # 3 consecutive failures before failover
  request_interval  = 10         # check every 10 seconds
  regions           = ["us-east-1", "us-west-2", "eu-west-1"]  # check from multiple regions
}

resource "aws_route53_record" "primary" {
  zone_id = var.hosted_zone_id
  name    = "claude-api.company.com"
  type    = "A"

  failover_routing_policy {
    type = "PRIMARY"
  }
  set_identifier  = "primary-us-east-1"
  health_check_id = aws_route53_health_check.primary.id
  alias {
    name                   = var.primary_alb_dns
    zone_id                = var.primary_alb_zone_id
    evaluate_target_health = false
  }
}

resource "aws_route53_record" "standby" {
  zone_id = var.hosted_zone_id
  name    = "claude-api.company.com"
  type    = "A"

  failover_routing_policy {
    type = "SECONDARY"   # receives traffic only when primary health check fails
  }
  set_identifier = "standby-us-west-2"
  alias {
    name                   = var.standby_alb_dns
    zone_id                = var.standby_alb_zone_id
    evaluate_target_health = false
  }
}
